 1	import React, { FC, useCallback } from 'react';
 2	
 3	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
 4	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 5	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { k8sUpdate, ListPageBody } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Button, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
 9	
10	import useEditTemplateAccessReview from '../../hooks/useIsTemplateEditable';
11	
12	import NetworkInterfaceList from './components/list/NetworkInterfaceList';
13	import TemplatesNetworkInterfaceModal from './components/modal/TemplatesNetworkInterfaceModal';
14	
15	type TemplateNetworkProps = {
16	  obj: V1Template;
17	};
18	
19	const TemplateNetwork: FC<TemplateNetworkProps> = ({ obj: template }) => {
20	  const { t } = useKubevirtTranslation();
21	  const { createModal } = useModal();
22	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
23	  const actionText = t('Add network interface');
24	
25	  const onSubmitTemplate = useCallback(
26	    (updatedTemplate: V1Template) =>
27	      k8sUpdate({
28	        data: updatedTemplate,
29	        model: TemplateModel,
30	        name: updatedTemplate?.metadata?.name,
31	        ns: updatedTemplate?.metadata?.namespace,
32	      }),
33	    [],
34	  );
35	
36	  return (
37	    <PageSection variant={PageSectionVariants.light}>
38	      <ListPageBody>
39	        <SidebarEditor<V1Template> onResourceUpdate={onSubmitTemplate} resource={template}>
40	          <Title className="list-page-create-button-margin" headingLevel="h2">
41	            {t('Network interfaces')}
42	          </Title>
43	
44	          <Button
45	            onClick={() =>
46	              createModal(({ isOpen, onClose }) => (
47	                <TemplatesNetworkInterfaceModal
48	                  headerText={actionText}
49	                  isOpen={isOpen}
50	                  onClose={onClose}
51	                  template={template}
52	                />
53	              ))
54	            }
55	            className="template-network-tab__button"
56	            isDisabled={!isTemplateEditable}
57	          >
58	            {actionText}
59	          </Button>
60	
61	          <NetworkInterfaceList template={template} />
62	        </SidebarEditor>
63	      </ListPageBody>
64	    </PageSection>
65	  );
66	};
67	
68	export default TemplateNetwork;

